import{_ as e,o as l,c as d,ag as i}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Git Aliase | Dotfiles (DE)","titleTemplate":":title","description":"Ueber 80 Git-Shell-Aliase fuer schnellere Commits, Branches, Diffs und Remotes. Beschleunigen Sie Ihre taeglichen Versionskontrollaufgaben.","frontmatter":{"title":"Git Aliase | Dotfiles","description":"Ueber 80 Git-Shell-Aliase fuer schnellere Commits, Branches, Diffs und Remotes. Beschleunigen Sie Ihre taeglichen Versionskontrollaufgaben.","lang":"de-DE","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Git Aliase preview","canonical":"/de/aliases/git/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Git Aliase","pageType":"docs","schemaType":"WebPage","metaTitle":"Git Aliase - Dotfiles (DE)","permalink":"/de/aliases/git/","sidebar":true,"meta":[{"name":"keywords","content":"git aliase, git verknuepfungen, git dotfiles, git commit alias, git branch alias, git push alias, shell, bash, zsh, linux, macos"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Ueber 80 Git-Shell-Aliase fuer schnellere Commits, Branches, Diffs und Remotes."},{"name":"twitter:title","content":"Git Aliase - Dotfiles"},{"name":"og:title","content":"Git Aliase - Dotfiles"},{"name":"og:description","content":"Ueber 80 Git-Shell-Aliase fuer schnellere Commits, Branches, Diffs und Remotes."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"de_DE"}]},"headers":[],"relativePath":"de/aliases/git/index.md","filePath":"de/aliases/git/index.md","lastUpdated":1773010926000}'),n={name:"de/aliases/git/index.md"};function a(s,t,o,g,r,c){return l(),d("div",null,[...t[0]||(t[0]=[i('<h1 id="git-aliase" tabindex="-1">Git Aliase <a class="header-anchor" href="#git-aliase" aria-label="Permalink to &quot;Git Aliase&quot;">​</a></h1><p>Optimieren Sie Ihren Versionskontroll-Workflow mit leistungsstarken Verknuepfungen.</p><h2 id="uebersicht" tabindex="-1">Uebersicht <a class="header-anchor" href="#uebersicht" aria-label="Permalink to &quot;Uebersicht&quot;">​</a></h2><p>Git-Aliase erstellen Verknuepfungen fuer haeufig verwendete Git-Befehle. Als Teil der <a href="https://github.com/sebastienrousseau/dotfiles" target="_blank" rel="noreferrer">Dotfiles</a>-Konfiguration werden diese Aliase automatisch ueber Chezmoi geladen.</p><p>In <code>git.aliases.sh</code> und <code>signing.aliases.sh</code> definiert, sind die Aliase in jeder Bash- oder Zsh-Sitzung nach der Installation verfuegbar.</p><h2 id="referenz" tabindex="-1">Referenz <a class="header-anchor" href="#referenz" aria-label="Permalink to &quot;Referenz&quot;">​</a></h2><h3 id="kern" tabindex="-1">Kern <a class="header-anchor" href="#kern" aria-label="Permalink to &quot;Kern&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>g</code></td><td style="text-align:left;"><code>git</code></td><td style="text-align:left;">Kurzform fuer git</td></tr><tr><td style="text-align:left;"><code>gtp</code></td><td style="text-align:left;"><code>git rev-parse --show-toplevel</code></td><td style="text-align:left;">Oberstes Verzeichnis des Repositories ausgeben</td></tr><tr><td style="text-align:left;"><code>grpa</code></td><td style="text-align:left;"><code>git rev-parse --abbrev-ref HEAD</code></td><td style="text-align:left;">Aktuellen Branch-Namen ausgeben</td></tr><tr><td style="text-align:left;"><code>gconfl</code></td><td style="text-align:left;"><code>git config --list</code></td><td style="text-align:left;">Alle Git-Konfigurationseinstellungen auflisten</td></tr><tr><td style="text-align:left;"><code>gconfr</code></td><td style="text-align:left;"><code>git config --local --get remote.origin.url</code></td><td style="text-align:left;">Remote-Origin-URL ausgeben</td></tr><tr><td style="text-align:left;"><code>gconfdiff</code></td><td style="text-align:left;"><code>git config alias.dcolor &quot;diff --color-words&quot;</code></td><td style="text-align:left;">Farbwort-Diff-Alias konfigurieren</td></tr></tbody></table><h3 id="arbeitsbereich" tabindex="-1">Arbeitsbereich <a class="header-anchor" href="#arbeitsbereich" aria-label="Permalink to &quot;Arbeitsbereich&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ga</code></td><td style="text-align:left;"><code>git add</code></td><td style="text-align:left;">Dateien stagen</td></tr><tr><td style="text-align:left;"><code>gaa</code></td><td style="text-align:left;"><code>git add --all</code></td><td style="text-align:left;">Alle Aenderungen stagen (verfolgt und unverfolgt)</td></tr><tr><td style="text-align:left;"><code>gad</code></td><td style="text-align:left;"><code>git add .</code></td><td style="text-align:left;">Alles im aktuellen Verzeichnis stagen</td></tr><tr><td style="text-align:left;"><code>gau</code></td><td style="text-align:left;"><code>git add --update</code></td><td style="text-align:left;">Aenderungen und Loeschungen stagen (keine neuen Dateien)</td></tr><tr><td style="text-align:left;"><code>gcl</code></td><td style="text-align:left;"><code>git clone</code></td><td style="text-align:left;">Repository klonen</td></tr><tr><td style="text-align:left;"><code>gin</code></td><td style="text-align:left;"><code>git init</code></td><td style="text-align:left;">Neues Git-Repository initialisieren</td></tr><tr><td style="text-align:left;"><code>gco</code></td><td style="text-align:left;"><code>git checkout</code></td><td style="text-align:left;">Branches wechseln oder Arbeitsdateien wiederherstellen</td></tr><tr><td style="text-align:left;"><code>gcb</code></td><td style="text-align:left;"><code>git checkout -b</code></td><td style="text-align:left;">Neuen Branch erstellen und wechseln</td></tr><tr><td style="text-align:left;"><code>gdis</code></td><td style="text-align:left;"><code>git checkout --</code></td><td style="text-align:left;">Aenderungen im Arbeitsverzeichnis verwerfen</td></tr><tr><td style="text-align:left;"><code>grs</code></td><td style="text-align:left;"><code>git restore</code></td><td style="text-align:left;">Arbeitsdateien wiederherstellen</td></tr><tr><td style="text-align:left;"><code>gmv</code></td><td style="text-align:left;"><code>git mv</code></td><td style="text-align:left;">Datei verschieben oder umbenennen</td></tr><tr><td style="text-align:left;"><code>grm</code></td><td style="text-align:left;"><code>git rm</code></td><td style="text-align:left;">Dateien aus Arbeitsbaum und Index entfernen</td></tr><tr><td style="text-align:left;"><code>grmc</code></td><td style="text-align:left;"><code>git rm --cached</code></td><td style="text-align:left;">Datei entstagen (auf Festplatte behalten)</td></tr><tr><td style="text-align:left;"><code>gst</code></td><td style="text-align:left;"><code>git status</code></td><td style="text-align:left;">Status des Arbeitsbaums anzeigen</td></tr><tr><td style="text-align:left;"><code>gsts</code></td><td style="text-align:left;"><code>git status --short</code></td><td style="text-align:left;">Status im Kurzformat</td></tr><tr><td style="text-align:left;"><code>gstsb</code></td><td style="text-align:left;"><code>git status --short --branch</code></td><td style="text-align:left;">Kurzstatus mit Branch- und Tracking-Info</td></tr><tr><td style="text-align:left;"><code>gsta</code></td><td style="text-align:left;"><code>git stash save</code></td><td style="text-align:left;">Aktuelle Aenderungen stashen</td></tr><tr><td style="text-align:left;"><code>gstp</code></td><td style="text-align:left;"><code>git stash pop</code></td><td style="text-align:left;">Neuesten Stash anwenden und entfernen</td></tr><tr><td style="text-align:left;"><code>gstd</code></td><td style="text-align:left;"><code>git stash drop</code></td><td style="text-align:left;">Neuesten Stash-Eintrag loeschen</td></tr><tr><td style="text-align:left;"><code>gclout</code></td><td style="text-align:left;"><code>git clean -df &amp;&amp; git checkout -- .</code></td><td style="text-align:left;">Alle Aenderungen und unverfolgte Dateien verwerfen</td></tr></tbody></table><h3 id="commits" tabindex="-1">Commits <a class="header-anchor" href="#commits" aria-label="Permalink to &quot;Commits&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gc</code></td><td style="text-align:left;"><code>git commit -a</code></td><td style="text-align:left;">Alle verfolgten Aenderungen committen</td></tr><tr><td style="text-align:left;"><code>gca</code></td><td style="text-align:left;"><code>git commit --amend</code></td><td style="text-align:left;">Letzten Commit aendern</td></tr><tr><td style="text-align:left;"><code>gcall</code></td><td style="text-align:left;"><code>git add -A &amp;&amp; git commit -av</code></td><td style="text-align:left;">Alles stagen und ausfuehrlich committen</td></tr><tr><td style="text-align:left;"><code>gcam</code></td><td style="text-align:left;"><code>git commit --amend --message</code></td><td style="text-align:left;">Commit mit neuer Nachricht aendern</td></tr><tr><td style="text-align:left;"><code>gcane</code></td><td style="text-align:left;"><code>git commit --amend --no-edit</code></td><td style="text-align:left;">Commit ohne Aenderung der Nachricht aendern</td></tr><tr><td style="text-align:left;"><code>gcm</code></td><td style="text-align:left;"><code>git commit --message</code></td><td style="text-align:left;">Commit mit Inline-Nachricht</td></tr></tbody></table><h3 id="diff-und-historie" tabindex="-1">Diff und Historie <a class="header-anchor" href="#diff-und-historie" aria-label="Permalink to &quot;Diff und Historie&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gd</code></td><td style="text-align:left;"><code>git diff</code></td><td style="text-align:left;">Ungestagete Aenderungen anzeigen</td></tr><tr><td style="text-align:left;"><code>gdch</code></td><td style="text-align:left;"><code>git diff --name-status</code></td><td style="text-align:left;">Namen und Status geaenderter Dateien anzeigen</td></tr><tr><td style="text-align:left;"><code>gdh</code></td><td style="text-align:left;"><code>git diff HEAD</code></td><td style="text-align:left;">Alle Aenderungen seit letztem Commit anzeigen</td></tr><tr><td style="text-align:left;"><code>gdstaged</code></td><td style="text-align:left;"><code>git diff --staged</code></td><td style="text-align:left;">Gestagete Aenderungen anzeigen</td></tr><tr><td style="text-align:left;"><code>gdcached</code></td><td style="text-align:left;"><code>git diff --cached</code></td><td style="text-align:left;">Aenderungen zwischen Index und HEAD anzeigen</td></tr><tr><td style="text-align:left;"><code>gdstat</code></td><td style="text-align:left;"><code>git diff --stat --ignore-space-change -r</code></td><td style="text-align:left;">Diffstat ohne Leerzeichenaenderungen generieren</td></tr><tr><td style="text-align:left;"><code>gl</code></td><td style="text-align:left;"><code>git log --since=&quot;last month&quot; --oneline</code></td><td style="text-align:left;">Einzeiliges Log des letzten Monats</td></tr><tr><td style="text-align:left;"><code>glg</code></td><td style="text-align:left;"><code>git log --graph --all --oneline --decorate</code></td><td style="text-align:left;">Graph-Log aller Branches</td></tr><tr><td style="text-align:left;"><code>glgg</code></td><td style="text-align:left;"><code>git log --oneline --graph --full-history --all --color --decorate</code></td><td style="text-align:left;">Vollstaendiges Graph-Log mit Farbe</td></tr><tr><td style="text-align:left;"><code>glc</code></td><td style="text-align:left;"><code>git log --oneline --reverse</code></td><td style="text-align:left;">Chronologisches einzeiliges Log</td></tr><tr><td style="text-align:left;"><code>gld</code></td><td style="text-align:left;"><code>git log --since=1-day-ago</code></td><td style="text-align:left;">Log der letzten 24 Stunden</td></tr><tr><td style="text-align:left;"><code>gldc</code></td><td style="text-align:left;"><code>git log -1 --date-order --format=%cI</code></td><td style="text-align:left;">ISO 8601-Datum des letzten Commits</td></tr><tr><td style="text-align:left;"><code>gldl</code></td><td style="text-align:left;"><code>git log --date=local</code></td><td style="text-align:left;">Log mit Daten in lokaler Zeitzone</td></tr><tr><td style="text-align:left;"><code>glf</code></td><td style="text-align:left;"><code>git log ORIG_HEAD.. --stat --no-merges</code></td><td style="text-align:left;">Neue Commits nach Fetch (ohne Merges)</td></tr><tr><td style="text-align:left;"><code>gll</code></td><td style="text-align:left;"><em>(dekoriertes Graph-Format)</em></td><td style="text-align:left;">Detailliertes Graph-Log mit Autor und GPG-Status</td></tr></tbody></table><h3 id="branches" tabindex="-1">Branches <a class="header-anchor" href="#branches" aria-label="Permalink to &quot;Branches&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gb</code></td><td style="text-align:left;"><code>git branch</code></td><td style="text-align:left;">Lokale Branches auflisten</td></tr><tr><td style="text-align:left;"><code>gbd</code></td><td style="text-align:left;"><code>git branch -d</code></td><td style="text-align:left;">Gemergten Branch loeschen</td></tr><tr><td style="text-align:left;"><code>gbl</code></td><td style="text-align:left;"><code>git branch -l</code></td><td style="text-align:left;">Branches nach Muster auflisten</td></tr><tr><td style="text-align:left;"><code>gbr</code></td><td style="text-align:left;"><code>git branch -r</code></td><td style="text-align:left;">Remote-Branches auflisten</td></tr><tr><td style="text-align:left;"><code>gbrd</code></td><td style="text-align:left;"><code>git branch -d -r</code></td><td style="text-align:left;">Remote-Tracking-Branch loeschen</td></tr><tr><td style="text-align:left;"><code>gbrsb</code></td><td style="text-align:left;"><code>git show-branch</code></td><td style="text-align:left;">Branches und ihre Commits anzeigen</td></tr><tr><td style="text-align:left;"><code>gswb</code></td><td style="text-align:left;"><code>git switch</code></td><td style="text-align:left;">Branches wechseln (modern)</td></tr><tr><td style="text-align:left;"><code>gcode</code></td><td style="text-align:left;"><code>git checkout main &amp;&amp; git branch --merged | xargs git branch --delete</code></td><td style="text-align:left;">Alle in main gemergten Branches loeschen</td></tr><tr><td style="text-align:left;"><code>gcom</code></td><td style="text-align:left;"><code>git checkout main &amp;&amp; git fetch origin --prune &amp;&amp; git reset --hard origin/main</code></td><td style="text-align:left;">Lokalen main auf Remote zuruecksetzen</td></tr></tbody></table><h3 id="remotes-und-push-pull" tabindex="-1">Remotes und Push/Pull <a class="header-anchor" href="#remotes-und-push-pull" aria-label="Permalink to &quot;Remotes und Push/Pull&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gf</code></td><td style="text-align:left;"><code>git fetch</code></td><td style="text-align:left;">Von Remote fetchen</td></tr><tr><td style="text-align:left;"><code>gp</code></td><td style="text-align:left;"><code>git pull</code></td><td style="text-align:left;">Von Remote pullen</td></tr><tr><td style="text-align:left;"><code>gph</code></td><td style="text-align:left;"><code>git push</code></td><td style="text-align:left;">Zu Remote pushen</td></tr><tr><td style="text-align:left;"><code>gpo</code></td><td style="text-align:left;"><code>git push origin</code></td><td style="text-align:left;">Zu origin pushen</td></tr><tr><td style="text-align:left;"><code>gpb</code></td><td style="text-align:left;"><code>git push --set-upstream origin $(git branch --show-current)</code></td><td style="text-align:left;">Pushen und Upstream fuer aktuellen Branch setzen</td></tr><tr><td style="text-align:left;"><code>gpoll</code></td><td style="text-align:left;"><code>git push origin --all</code></td><td style="text-align:left;">Alle Branches zu origin pushen</td></tr><tr><td style="text-align:left;"><code>gpull</code></td><td style="text-align:left;"><code>git pull</code></td><td style="text-align:left;">Von Remote pullen</td></tr><tr><td style="text-align:left;"><code>gpush</code></td><td style="text-align:left;"><code>git push</code></td><td style="text-align:left;">Zu Remote pushen</td></tr><tr><td style="text-align:left;"><code>gr</code></td><td style="text-align:left;"><code>git remote</code></td><td style="text-align:left;">Remotes verwalten</td></tr><tr><td style="text-align:left;"><code>gra</code></td><td style="text-align:left;"><code>git remote add</code></td><td style="text-align:left;">Neuen Remote hinzufuegen</td></tr><tr><td style="text-align:left;"><code>grall</code></td><td style="text-align:left;"><code>git remote | xargs -L1 git push --all</code></td><td style="text-align:left;">Alle Branches zu allen Remotes pushen</td></tr><tr><td style="text-align:left;"><code>grao</code></td><td style="text-align:left;"><code>git remote add origin</code></td><td style="text-align:left;">Origin-Remote hinzufuegen</td></tr><tr><td style="text-align:left;"><code>grv</code></td><td style="text-align:left;"><code>git remote -v</code></td><td style="text-align:left;">Remote-URLs anzeigen</td></tr></tbody></table><h3 id="revert-und-reset" tabindex="-1">Revert und Reset <a class="header-anchor" href="#revert-und-reset" aria-label="Permalink to &quot;Revert und Reset&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>grev</code></td><td style="text-align:left;"><code>git revert</code></td><td style="text-align:left;">Commit rueckgaengig machen</td></tr><tr><td style="text-align:left;"><code>grevnc</code></td><td style="text-align:left;"><code>git revert --no-commit</code></td><td style="text-align:left;">Ohne Auto-Commit rueckgaengig machen</td></tr><tr><td style="text-align:left;"><code>grb</code></td><td style="text-align:left;"><code>git rebase</code></td><td style="text-align:left;">Aktuellen Branch rebasen</td></tr><tr><td style="text-align:left;"><code>grbk</code></td><td style="text-align:left;"><code>git reset --soft HEAD^</code></td><td style="text-align:left;">Letzten Commit rueckgaengig, Aenderungen gestaget behalten</td></tr><tr><td style="text-align:left;"><code>grescl</code></td><td style="text-align:left;"><code>git reset --hard HEAD~1 &amp;&amp; git clean -fd</code></td><td style="text-align:left;">Hard-Reset und unverfolgte Dateien bereinigen</td></tr><tr><td style="text-align:left;"><code>gresh</code></td><td style="text-align:left;"><code>git reset --hard HEAD~1</code></td><td style="text-align:left;">Hard-Reset zum vorherigen Commit</td></tr><tr><td style="text-align:left;"><code>gresp</code></td><td style="text-align:left;"><code>git reset --hard &amp;&amp; git clean -ffdx</code></td><td style="text-align:left;">Alles auf urspruenglichen Zustand zuruecksetzen</td></tr><tr><td style="text-align:left;"><code>gress</code></td><td style="text-align:left;"><code>git reset --soft HEAD~1</code></td><td style="text-align:left;">Soft-Reset (Aenderungen gestaget behalten)</td></tr></tbody></table><h3 id="submodule" tabindex="-1">Submodule <a class="header-anchor" href="#submodule" aria-label="Permalink to &quot;Submodule&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gsm</code></td><td style="text-align:left;"><code>git submodule</code></td><td style="text-align:left;">Submodule verwalten</td></tr><tr><td style="text-align:left;"><code>gsmi</code></td><td style="text-align:left;"><code>git submodule init</code></td><td style="text-align:left;">Submodule initialisieren</td></tr><tr><td style="text-align:left;"><code>gsma</code></td><td style="text-align:left;"><code>git submodule add</code></td><td style="text-align:left;">Submodul hinzufuegen</td></tr><tr><td style="text-align:left;"><code>gsms</code></td><td style="text-align:left;"><code>git submodule sync</code></td><td style="text-align:left;">Submodul-URLs mit .gitmodules synchronisieren</td></tr><tr><td style="text-align:left;"><code>gsmu</code></td><td style="text-align:left;"><code>git submodule update</code></td><td style="text-align:left;">Submodule aktualisieren</td></tr><tr><td style="text-align:left;"><code>gsmui</code></td><td style="text-align:left;"><code>git submodule update --init</code></td><td style="text-align:left;">Submodule aktualisieren und initialisieren</td></tr><tr><td style="text-align:left;"><code>gsmuir</code></td><td style="text-align:left;"><code>git submodule update --init --recursive</code></td><td style="text-align:left;">Submodule aktualisieren, initialisieren und rekursiv</td></tr></tbody></table><h3 id="werkzeuge" tabindex="-1">Werkzeuge <a class="header-anchor" href="#werkzeuge" aria-label="Permalink to &quot;Werkzeuge&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gg</code></td><td style="text-align:left;"><code>git grep</code></td><td style="text-align:left;">Repository-Inhalte durchsuchen</td></tr><tr><td style="text-align:left;"><code>gbs</code></td><td style="text-align:left;"><code>git bisect</code></td><td style="text-align:left;">Binaersuche fuer fehlerverursachenden Commit</td></tr><tr><td style="text-align:left;"><code>undopush</code></td><td style="text-align:left;"><code>git push -f origin HEAD^:master</code></td><td style="text-align:left;">Letzten Push zu master erzwungen rueckgaengig machen</td></tr></tbody></table><h3 id="signierung-und-sicherheit" tabindex="-1">Signierung und Sicherheit <a class="header-anchor" href="#signierung-und-sicherheit" aria-label="Permalink to &quot;Signierung und Sicherheit&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>enable-signing</code></td><td style="text-align:left;"><em>(interaktiver Assistent)</em></td><td style="text-align:left;">GPG- oder SSH-Commit-Signierung konfigurieren</td></tr><tr><td style="text-align:left;"><code>verify-signatures</code></td><td style="text-align:left;"><code>git log --show-signature -n 10</code></td><td style="text-align:left;">Signaturen der letzten 10 Commits verifizieren</td></tr><tr><td style="text-align:left;"><code>check-signing</code></td><td style="text-align:left;"><code>git config --list | grep &quot;gpg|signing&quot;</code></td><td style="text-align:left;">Aktuelle Signierungskonfiguration pruefen</td></tr></tbody></table>',26)])])}const x=e(n,[["render",a]]);export{h as __pageData,x as default};
